import icon from "../assets/icon.png";

const Header = () => {
    return (
        <header>
            <section>
                <div>
                <img src={icon} className="scale-75"/>
                <h1 style={{ fontFamily: 'Viga-Regular' }} className="uppercase text-5xl text-sky-700 pt-2">Film Focusd</h1>
                </div>
            </section>
        </header>
    )
}

export default Header;
